class Solution:
    def searchMatrix(self, m: list[list[int]], target: int) -> bool:
        if not m or not m[0]:
            return False
        i, j = 0, len(m[0]) - 1         # 从右上角出发
        while i < len(m) and j >= 0:
            if m[i][j] == target:
                return True
            if m[i][j] > target:        # 当前值偏大 -> 左移(排除这一列)
                j -= 1
            else:                       # 当前值偏小 -> 下移(排除这一行)
                i += 1
        return False
